import {withSentryConfig} from '@sentry/nextjs';
import type { NextConfig } from 'next';

const nextConfig: NextConfig = {
  reactStrictMode: true,
  typedRoutes: true,
  typescript: {
    ignoreBuildErrors: true,
  },
  outputFileTracingRoot: __dirname,
  async headers() {
    return [
      {
        source: '/(.*)',
        headers: [
          { key: 'X-Frame-Options', value: 'DENY' },
          { key: 'Referrer-Policy', value: 'strict-origin-when-cross-origin' },
          { key: 'X-Content-Type-Options', value: 'nosniff' },
          { key: 'X-DNS-Prefetch-Control', value: 'off' },
          {
            key: 'Content-Security-Policy',
            value: (() => {
              const _isDev = process.env.NODE_ENV !== 'production';
              const supabase = process.env.NEXT_PUBLIC_SUPABASE_URL || '';
              const supabaseOrigin = (() => {
                try { return new URL(supabase).origin; } catch { return ''; }
              })();
              // Allow inline & wasm eval also in prod to avoid blocking Next boot scripts in absence of nonces
              const scriptSrc = "'self' 'unsafe-inline' 'unsafe-eval' 'wasm-unsafe-eval'";
              const connectSrc = ["'self'", 'https:', 'ws:', 'wss:', supabaseOrigin].filter(Boolean).join(' ');
              return [
                "default-src 'self'",
                "img-src 'self' data: blob: https:",
                `script-src ${scriptSrc}`,
                "style-src 'self' 'unsafe-inline'",
                `connect-src ${connectSrc}`
              ].join('; ');
            })()
          }
        ]
      }
    ];
  }
};

export default withSentryConfig(nextConfig, {
  // For all available options, see:
  // https://www.npmjs.com/package/@sentry/webpack-plugin#options

  org: "emir-ow",

  project: "c-rep",

  // Only print logs for uploading source maps in CI
  silent: !process.env.CI,

  // For all available options, see:
  // https://docs.sentry.io/platforms/javascript/guides/nextjs/manual-setup/

  // Upload a larger set of source maps for prettier stack traces (increases build time)
  widenClientFileUpload: true,
  sourcemaps: {
    // Upload sourcemaps (if SENTRY_AUTH_TOKEN is provided in CI) and remove them from build output
    deleteSourcemapsAfterUpload: true,
  },

  // Uncomment to route browser requests to Sentry through a Next.js rewrite to circumvent ad-blockers.
  // This can increase your server load as well as your hosting bill.
  // Note: Check that the configured route will not match with your Next.js middleware, otherwise reporting of client-
  // side errors will fail.
  // tunnelRoute: "/monitoring",

  // Automatically tree-shake Sentry logger statements to reduce bundle size
  disableLogger: true,

  // Enables automatic instrumentation of Vercel Cron Monitors. (Does not yet work with App Router route handlers.)
  // See the following for more information:
  // https://docs.sentry.io/product/crons/
  // https://vercel.com/docs/cron-jobs
  automaticVercelMonitors: true
});

import Link from 'next/link';
import { createClient } from '@/lib/server';
import { redirect } from 'next/navigation';
import type { Route } from 'next';
import { formatCo2eTons } from '@/lib/units';
import { ConfirmSubmitButton } from '@/components/ConfirmSubmitButton';
import { updateEntryNotesAction, deleteEntryAction } from '../actions';
import { EvidenceUploader } from '@/components/EvidenceUploader';
import { EvidenceList } from '@/components/EvidenceList';
import { deleteEvidence } from '@/app/projects/[id]/evidence/server';
import { SmartBackLink } from '@/components/SmartBackLink';

export default async function EntryDetailPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) redirect((`/login?next=${encodeURIComponent(`/entries/${id}`)}` as unknown) as Route);

  const [{ data: entry, error }, { data: evidence }] = await Promise.all([
    supabase
      .from('entries')
      .select('id, project_id, date, type, category, activity_id, amount, unit, notes, co2e_value, co2e_unit, projects(name), activities(name, key)')
      .eq('id', id)
      .maybeSingle(),
    supabase
      .from('evidence_files')
      .select('id, file_path, mime, size, created_at, entry_id, original_filename')
      .eq('entry_id', id)
      .order('created_at', { ascending: false })
  ]);

  if (error) return <div>Kayıt yüklenemedi: {String(error.message || error)}</div>;
  if (!entry) return <div>Kayıt bulunamadı.</div>;

  const co2e = Number(entry.co2e_value ?? 0);
  const co2eFmt = Number.isFinite(co2e) && co2e > 0 ? formatCo2eTons(co2e, 3) : null;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <SmartBackLink
            entriesHref="/entries"
            projectHref={`/projects/${entry.project_id}#entries`}
          />
          <div>
            <h1 className="text-2xl font-semibold leading-none">Aktivite Detayı</h1>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <form action={deleteEntryAction}>
            <input type="hidden" name="entryId" value={entry.id} />
            <input type="hidden" name="redirectTo" value={((`/projects/${entry.project_id}#entries` as unknown) as string)} />
            <ConfirmSubmitButton
              className="px-3 py-1.5 rounded-md bg-red-500/10 hover:bg-red-500/20 border border-red-500/30 text-red-400 hover:text-red-300 transition-colors"
              message="Bu aktiviteyi silmek istediğinize emin misiniz?"
            >
              Sil
            </ConfirmSubmitButton>
          </form>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-6">
        <div className="space-y-6">
          <div className="rounded-lg border border-white/10 bg-white/5 p-4">
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <InfoRow label="Proje">
                {entry.project_id ? (
                  <Link className="text-leaf-400 hover:underline" href={`/projects/${entry.project_id}`}>{(entry as any).projects?.name || entry.project_id}</Link>
                ) : '—'}
              </InfoRow>
              <InfoRow label="Tarih">{new Date(entry.date as any).toLocaleDateString()}</InfoRow>
              <InfoRow label="Aktivite">{(entry as any).activities?.name || entry.category || '—'}</InfoRow>
              <InfoRow label="Tür">{entry.type}</InfoRow>
              <InfoRow label="Miktar">{entry.amount} {entry.unit}</InfoRow>
              <InfoRow label="CO₂e">{co2eFmt ? `${co2eFmt.value} ${co2eFmt.unit}` : '-'}</InfoRow>
            </div>
            <div className="mt-4">
              <form id="notes-form" action={updateEntryNotesAction} className="flex items-center gap-2">
                <input type="hidden" name="entryId" value={entry.id} />
                <input
                  name="notes"
                  defaultValue={(entry as any).notes || ''}
                  placeholder="Notlar"
                  className="form-input py-2 px-3 flex-1"
                />
              </form>
            </div>
          </div>

          <div id="evidence" className="rounded-lg border border-white/10 bg-white/5 p-4 scroll-mt-24">
            <div className="text-sm font-medium mb-3 text-white/80">Kanıtlar</div>
            <EvidenceUploader projectId={entry.project_id} entryId={entry.id} onUploaded={undefined} />
            <div className="mt-4">
              {(evidence || []).length === 0 ? (
                <div className="text-sm text-white/60">Henüz kanıt eklenmemiş.</div>
              ) : (
                <EvidenceList projectId={entry.project_id} items={evidence as any} />
              )}
            </div>
          </div>
        </div>
      </div>

      <div className="sticky bottom-0 z-10 bg-gradient-to-t from-ocean-950/80 to-transparent backdrop-blur supports-[backdrop-filter]:backdrop-blur flex justify-end pt-4 mt-6 border-t border-white/10">
        <button
          form="notes-form"
          type="submit"
          name="redirectTo"
          value={`/projects/${entry.project_id}#entries`}
          className="px-5 py-2.5 rounded-lg bg-gradient-to-r from-leaf-600 to-ocean-600 hover:from-leaf-500 hover:to-ocean-500 text-white shadow-md hover:shadow-lg transition-all border border-white/10"
        >
          Kaydet ve Çık
        </button>
      </div>
    </div>
  );
}

function InfoRow({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div className="flex flex-col">
      <div className="text-xs text-white/60">{label}</div>
      <div className="text-sm text-white/90">{children}</div>
    </div>
  );
}

import type { ReactNode } from 'react';
import type { Viewport } from 'next';
import { createClient } from '@/lib/server';
import { Header } from '@/components/Header';
import { SkipLink } from '@/components/SkipLink';
import './globals.css';
import { cookies as _cookies } from 'next/headers';
import { redirect as _redirect } from 'next/navigation';
import { revalidatePath } from 'next/cache';
import { ToastContainer } from '@/components/Toast';

export default async function RootLayout({ children }: { children: ReactNode }) {
  const supabase = await createClient();
  const { data } = await supabase.auth.getUser();
  const user = data?.user ?? null;

  // Bootstrap default organization for first-time users
  if (user) {
    try {
      const { data: orgs } = await supabase
        .from('organization_members')
        .select('organization_id')
        .eq('user_id', user.id)
        .limit(1);
      if (!orgs || orgs.length === 0) {
        await supabase.rpc('create_organization', { p_name: 'Default Org', p_owner: user.id });
        revalidatePath('/dashboard');
      }
    } catch {}
  }

  return (
    <html lang="tr">
      <body className="min-h-screen bg-emerald-950 text-green-100">
        <SkipLink />
  <Header user={user ? { email: user.email } : null} />
  <main id="main" className="app-container py-8 safe-px safe-pb">{children}</main>
        <ToastContainer />
      </body>
    </html>
  );
}

export const viewport: Viewport = {
  width: 'device-width',
  initialScale: 1,
  viewportFit: 'cover'
};

import { createClient } from '@/lib/server';
import { revalidatePath } from 'next/cache';
import { redirect } from 'next/navigation';
import type { Route } from 'next';
import Link from 'next/link';
import { WeatherQuickSet } from '@/components/WeatherQuickSet';
import { DailyLogPhotoUploader } from '@/components/DailyLogPhotoUploader';
import { DailyLogPhotoList } from '@/components/DailyLogPhotoList';
import { DailyLogManpowerSection } from '@/components/DailyLogManpowerSection';
import { DailyLogEquipmentSection } from '@/components/DailyLogEquipmentSection';
import { DailyLogMaterialsSection } from '@/components/DailyLogMaterialsSection';
import MaterialsWithDialog from '@/components/MaterialsWithDialog';
import { addActivityToDailyLog } from '@/app/actions/logs';

export default async function DailyLogDetailPage({ params }: any) {
  const { id, logId } = params;
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) redirect((`/login?error=login_required` as unknown) as Route);

  const { data: log, error } = await supabase
    .from('daily_logs')
    .select('*')
    .eq('project_id', id)
    .eq('id', logId)
    .maybeSingle();
  if (error) return <div>Günlük yüklenemedi: {error.message}</div>;
  if (!log) return <div>Günlük bulunamadı</div>;

  // Fetch project information
  const { data: project } = await supabase
    .from('projects')
    .select('name')
    .eq('id', id)
    .maybeSingle();

  const [manpowerRes, equipmentRes, materialsRes] = await Promise.all([
    supabase.from('daily_log_manpower').select('*').eq('log_id', logId).order('created_at', { ascending: false }),
    supabase.from('daily_log_equipment').select('*').eq('log_id', logId).order('created_at', { ascending: false }),
    supabase
      .from('daily_log_materials')
      .select('*, activities(name, default_unit, units)')
      .eq('log_id', logId)
      .order('created_at', { ascending: false })
  ]);

  const manpower = manpowerRes.data || [];
  const equipment = equipmentRes.data || [];
  const materials = materialsRes.data || [];

  async function setWeather(formData: FormData) {
    'use server';
    const supabase = await createClient();
    const weather = String(formData.get('weather') || '');
    const { error } = await supabase.from('daily_logs').update({ weather }).eq('id', logId);
    if (error) throw new Error(error.message);
    // no redirect; client will update state
  }

  // Optional: placeholder server action to set suggested weather value
  async function setSuggestedWeather() {
    'use server';
    const supabase = await createClient();
    // Placeholder suggestion logic. Later, fetch real data using project location.
    const suggestion = 'Güneşli';
    const { error } = await supabase.from('daily_logs').update({ weather: suggestion }).eq('id', logId);
    if (error) throw new Error(error.message);
    // return value so client can reflect it immediately
    return { weather: suggestion } as any;
  }

  async function saveSummary(formData: FormData) {
    'use server';
    const supabase = await createClient();
    const work_summary = String(formData.get('work_summary') || '');
    const { error } = await supabase.from('daily_logs').update({ work_summary }).eq('id', logId);
    if (error) redirect((`/projects/${id}/daily-logs?error=${encodeURIComponent(error.message)}` as unknown) as Route);
    // Ensure calendar list and detail page are fresh
    revalidatePath((`/projects/${id}/daily-logs` as unknown) as Route);
    revalidatePath((`/projects/${id}/daily-logs/${logId}` as unknown) as Route);
    // Go back to calendar view after saving
    redirect((`/projects/${id}/daily-logs` as unknown) as Route);
  }

  // Remove heavy redirect-based forms for manpower/equipment/materials; use client sections for instant UX

  // Fetch activities for material select
  const { data: activities } = await supabase.from('activities').select('id, name, default_unit, units').order('name');

  // Bind server action to this specific logId to avoid serializing params in client
  async function addMaterial(formData: FormData) {
    'use server';
    return await addActivityToDailyLog(logId, formData);
  }

  return (
    <div className="p-4 md:p-6 space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-semibold">{new Date(log.date).toLocaleDateString(undefined, { weekday:'long', year:'numeric', month:'long', day:'numeric' })} Günlüğü</h1>
          <div className="text-white/70 text-sm">{project?.name || 'Proje'}</div>
        </div>
        <Link href={( `/projects/${id}/daily-logs` as unknown) as Route} className="px-3 py-1.5 rounded border border-white/10 bg-white/10">← Listeye Dön</Link>
      </div>

  {/* Materials first */}
  <MaterialsWithDialog projectId={id} logId={logId} activities={(activities as any) || []} initial={materials as any} dateDefault={log.date} action={addMaterial} />

  {/* Weather - quick set without full page reload */}
  <WeatherQuickSet current={log.weather} onSet={setWeather} onSuggest={setSuggestedWeather} />

      {/* Work Summary */}
      <div className="glass rounded border border-white/10 p-6">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-leaf-500/20 to-ocean-500/20 flex items-center justify-center">
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-leaf-400">
              <path d="M9 11l3 3L22 4"/>
              <path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/>
            </svg>
          </div>
          <div>
            <div className="font-medium text-lg">Yapılan İşler (Özet)</div>
            <div className="text-white/60 text-sm">Günün gerçekleştirilen aktivitelerini detaylandırın</div>
          </div>
        </div>
        
        <form id="summary-form" action={saveSummary} className="space-y-4">
          <div className="bg-white/5 border border-white/10 rounded-xl p-4">
            <textarea 
              name="work_summary" 
              defaultValue={log.work_summary ?? ''} 
              className="w-full min-h-[160px] bg-transparent border-none resize-none focus:outline-none text-white placeholder-white/40 text-sm leading-relaxed" 
              placeholder="Örnek format:
• A Blok 2. kat kolon kalıpları çakıldı
• Beton dökümü tamamlandı (150 m³)
• Demir donatı yerleştirme işlemleri başladı
• Kalıp temizlik çalışmaları yapıldı
• Malzeme sevkiyatı gerçekleştirildi"
            />
          </div>
          <div className="flex items-center justify-end">
            <div className="text-xs text-white/40">
              Son güncelleme: {log.updated_at ? new Date(log.updated_at).toLocaleString('tr-TR') : 'Henüz kaydedilmedi'}
            </div>
          </div>
        </form>
      </div>
      

      {/* Manpower */}
      <DailyLogManpowerSection logId={logId} initial={manpower as any} />

      {/* Equipment */}
      <DailyLogEquipmentSection logId={logId} initial={equipment as any} />


      {/* Photos */}
      <details className="glass rounded-lg border border-white/20 p-4 group hover:border-indigo-400/40 transition-all duration-200">
        <summary className="cursor-pointer font-medium mb-3 flex items-center gap-2 hover:text-leaf-300 transition-all duration-200 list-none">
          <div className="flex items-center gap-2 flex-1">
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-indigo-400">
              <rect width="18" height="18" x="3" y="3" rx="2" ry="2"/>
              <circle cx="9" cy="9" r="2"/>
              <path d="m21 15-3.086-3.086a2 2 0 0 0-2.828 0L6 21"/>
            </svg>
            Fotoğraflar
            <span className="text-xs text-white/50">Günlük fotoğraflar</span>
          </div>
          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-white/60 transition-transform duration-200 group-open:rotate-180">
            <path d="m6 9 6 6 6-6"/>
          </svg>
        </summary>
        <div className="mb-3">
          <DailyLogPhotoUploader projectId={id} logId={logId} />
        </div>
        <DailyLogPhotoList 
          projectId={id} 
          logId={logId} 
          photos={Array.isArray(log.photos) ? log.photos : []} 
        />
      </details>

      {/* Bottom single Save button (at the very end of the page) */}
      <div className="mt-6 flex items-center justify-end">
        <button
          type="submit"
          form="summary-form"
          className="btn-primary px-6 py-2.5 rounded-lg flex items-center gap-2"
        >
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"/>
          </svg>
          Günlüğü Kaydet
        </button>
      </div>
    </div>
  );
}

import { createClient } from '@/lib/server';
import { redirect } from 'next/navigation';
import { revalidatePath } from 'next/cache';
import type { Route } from 'next';
import Link from 'next/link';

async function getSignedUrl(supabase: any, projectId: string, path: string) {
  const { data: revRows, error: revErr } = await supabase
    .from('document_revisions')
    .select('id, file_path, documents!inner(project_id)')
    .eq('file_path', path)
    .eq('documents.project_id', projectId)
    .limit(1);
  if (revErr || !revRows?.length) return null;
  const storageKey = path.replace(/^project-files\//, '');
  const { data } = await supabase.storage.from('project-files').createSignedUrl(storageKey, 60 * 5);
  return data?.signedUrl || null;
}

export default async function DocumentDetailPage({ params, searchParams }: { params: { id: string, docId: string }, searchParams?: { [key: string]: string | string[] | undefined } }) {
  const projectId = params.id;
  const docId = params.docId;

  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) redirect((`/login?error=login_required` as unknown) as Route);

  // Fetch document and all revisions
  const { data: doc, error: docErr } = await supabase
    .from('documents')
    .select('id, project_id, code, name, current_revision')
    .eq('id', docId)
    .single();
  if (docErr || !doc) return <div>Doküman bulunamadı</div>;

  const { data: revs, error: revErr } = await supabase
    .from('document_revisions')
    .select('id, rev_no, file_path, mime, size, note, created_at, created_by')
    .eq('document_id', docId)
    .order('rev_no', { ascending: false });
  if (revErr) return <div>Revizyonlar yüklenemedi: {revErr.message}</div>;

  // Flash messages via query params
  const flashError = typeof searchParams?.error === 'string' ? decodeURIComponent(searchParams!.error) : '';
  const flashSuccess = typeof searchParams?.success === 'string' ? decodeURIComponent(searchParams!.success) : '';

  async function renameAction(formData: FormData) {
    'use server';
    const name = String(formData.get('name') || '').trim();
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    // Ensure editor
    const { data: d } = await supabase.from('documents').select('id').eq('id', docId).single();
    if (!d) return;
    await supabase.from('documents').update({ name }).eq('id', docId);
    revalidatePath(`/projects/${projectId}/documents/${docId}`);
  }

  async function renameCodeAction(formData: FormData) {
    'use server';
    const code = String(formData.get('code') || '').trim();
    if (!code) return;
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    // Ensure unique per project
    const { data: docRow } = await supabase.from('documents').select('project_id').eq('id', docId).single();
    if (!docRow) redirect((`/projects/${projectId}/documents/${docId}?error=${encodeURIComponent('Doküman bulunamadı')}` as unknown) as Route);
    const { data: exists } = await supabase
      .from('documents')
      .select('id')
      .eq('project_id', docRow.project_id)
      .eq('code', code)
      .neq('id', docId)
      .limit(1);
    if (exists && exists.length > 0) {
      redirect((`/projects/${projectId}/documents/${docId}?error=${encodeURIComponent('Bu kod bu projede zaten kullanılıyor. Lütfen farklı bir kod deneyin.')}` as unknown) as Route);
    }
    const { error: updErr } = await supabase.from('documents').update({ code }).eq('id', docId);
    if (updErr) {
      // Fallback: unique violation or other error
      const msg = updErr.code === '23505'
        ? 'Bu kod bu projede zaten kullanılıyor. Lütfen farklı bir kod deneyin.'
        : 'Kod güncellenirken hata oluştu.';
      redirect((`/projects/${projectId}/documents/${docId}?error=${encodeURIComponent(msg)}` as unknown) as Route);
    }
    revalidatePath(`/projects/${projectId}/documents/${docId}`);
    redirect((`/projects/${projectId}/documents/${docId}?success=${encodeURIComponent('Kod güncellendi.')}` as unknown) as Route);
  }

  async function revertAction(formData: FormData) {
    'use server';
    const rev = Number(formData.get('rev'));
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    const { error } = await supabase.rpc('set_document_current_revision', { p_document: docId, p_rev: rev, p_actor: user.id });
    if (error) console.error(error);
    revalidatePath(`/projects/${projectId}/documents/${docId}`);
  }

  async function deleteAction() {
    'use server';
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    await supabase.from('documents').delete().eq('id', docId);
    redirect((`/projects/${projectId}/documents` as unknown) as Route);
  }

  async function deleteRevisionAction(formData: FormData) {
    'use server';
    const rev = Number(formData.get('rev'));
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    // Ensure not current revision
    const { data: d } = await supabase.from('documents').select('current_revision').eq('id', docId).single();
    if (!d || d.current_revision === rev) return;
    // Get file_path for storage cleanup before deleting
    const { data: revRow } = await supabase
      .from('document_revisions')
      .select('file_path')
      .eq('document_id', docId)
      .eq('rev_no', rev)
      .single();
    await supabase.from('document_revisions').delete().eq('document_id', docId).eq('rev_no', rev);
    // Best-effort: remove file from Storage
    try {
      if (revRow?.file_path) {
        const storageKey = revRow.file_path.replace(/^project-files\//, '');
        await supabase.storage.from('project-files').remove([storageKey]);
      }
      revalidatePath(`/projects/${projectId}/documents/${docId}`);
      redirect((`/projects/${projectId}/documents/${docId}?success=${encodeURIComponent('Revizyon silindi.')}` as unknown) as Route);
    } catch (e) {
      // ignore storage errors; DB delete already happened
      revalidatePath(`/projects/${projectId}/documents/${docId}`);
      redirect((`/projects/${projectId}/documents/${docId}?error=${encodeURIComponent('Revizyon verisi silindi ancak dosya kaldırılamadı.')}` as unknown) as Route);
    }
  }

  return (
    <div className="p-4 md:p-6 space-y-6">
      {(flashError || flashSuccess) && (
        <div className={`rounded border px-3 py-2 text-sm ${flashError ? 'border-red-500/40 text-red-300 bg-red-500/10' : 'border-emerald-500/40 text-emerald-300 bg-emerald-500/10'}`}>
          {flashError || flashSuccess}
        </div>
      )}
      <div className="flex items-center justify-between">
        <div>
          <div className="text-white/70 text-xs mb-1">Proje #{projectId}</div>
          <h1 className="text-xl font-semibold">{doc.code} – {doc.name}</h1>
        </div>
        <div className="flex items-center gap-2">
          <Link href={( `/projects/${projectId}/documents` as unknown) as Route} className="px-3 py-1.5 rounded border border-white/10 bg-white/10">← Liste</Link>
          <form action={deleteAction}>
            <button className="px-3 py-1.5 rounded border border-red-500/40 text-red-300 hover:bg-red-500/10">Sil</button>
          </form>
        </div>
      </div>

      <div className="glass rounded border border-white/10 p-4 space-y-4">
        <div>
          <div className="font-medium">Adı Değiştir</div>
          <form action={renameAction} className="flex items-center gap-2 mt-2">
            <input name="name" defaultValue={doc.name} className="form-input w-full max-w-md" />
            <button className="btn-primary">Kaydet</button>
          </form>
        </div>
        <div>
          <div className="font-medium">Kodu Değiştir</div>
          <form action={renameCodeAction} className="flex items-center gap-2 mt-2">
            <input name="code" defaultValue={doc.code} className="form-input w-full max-w-md" />
            <button className="px-3 py-1.5 rounded border border-white/10 bg-white/10 hover:bg-white/20">Kodu Kaydet</button>
          </form>
          <div className="text-xs text-white/60 mt-1">Not: Mevcut dosyalar eski klasörde kalır; yeni yüklemeler yeni kod klasörüne gidecek.</div>
        </div>
      </div>

      <div className="glass rounded border border-white/10 p-4">
        <div className="font-medium mb-2">Revizyonlar</div>
        <div className="space-y-2">
          {(revs || []).map(async (r) => {
            const download = `/api/documents/download?project=${projectId}&path=${encodeURIComponent(r.file_path)}`;
            const isCurrent = r.rev_no === doc.current_revision;
            const canPreview = r.mime?.startsWith('image/') || r.mime === 'application/pdf';
            const signed = canPreview ? await getSignedUrl(supabase, projectId, r.file_path) : null;
            return (
              <div key={r.id} className="rounded border border-white/10 bg-white/5 p-3">
                <div className="flex items-center justify-between">
                  <div className="text-sm">
                    <span className="font-mono bg-white/10 px-1.5 py-0.5 rounded mr-2">Rev.{String(r.rev_no).padStart(2, '0')}</span>
                    <span className="text-white/70">{new Date(r.created_at).toLocaleString()}</span>
                    {r.note && <span className="ml-2 text-white/60 italic">“{r.note}”</span>}
                  </div>
                  <div className="flex items-center gap-2 text-xs">
                    <a className="px-2 py-1 rounded border border-white/10 bg-white/10 hover:bg-white/20" href={download}>İndir</a>
                    {!isCurrent && (
                      <form action={revertAction}>
                        <input type="hidden" name="rev" value={r.rev_no} />
                        <button className="px-2 py-1 rounded border border-white/10 hover:bg-white/10">Bu sürümü kullan</button>
                      </form>
                    )}
                    {!isCurrent && (
                      <form action={deleteRevisionAction}>
                        <input type="hidden" name="rev" value={r.rev_no} />
                        <button className="px-2 py-1 rounded border border-red-500/40 text-red-300 hover:bg-red-500/10">Sil</button>
                      </form>
                    )}
                    {isCurrent && <span className="text-emerald-300">(Aktif)</span>}
                  </div>
                </div>
                {canPreview && signed && (
                  <div className="mt-3">
                    {r.mime?.startsWith('image/') ? (
                       
                      <img src={signed} alt={`Rev ${r.rev_no}`} className="max-h-96 rounded border border-white/10" />
                    ) : (
                      <iframe src={signed} className="w-full h-96 rounded border border-white/10" />
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

"use client";
import { useEffect, useMemo, useRef, useState } from 'react';
import { supabaseBrowser } from '@/lib/client';

export default function ActivitySelect({ value, onChange }: { value: string; onChange: (v: string) => void }) {
  // Keep only the fields we render after translation
  const [items, setItems] = useState<Array<{ id: string; name: string; type: string }>>([]);
  const [favorites, setFavorites] = useState<Set<string>>(new Set());
  const [q, setQ] = useState('');
  const [loading, setLoading] = useState(false);
  const [open, setOpen] = useState(false);
  const [highlight, setHighlight] = useState<number>(-1);
  const boxRef = useRef<HTMLDivElement | null>(null);
  const inputRef = useRef<HTMLInputElement | null>(null);

  // Minimal TR translations for common categories/keys coming from seeds/imports
  const TR_MAP: Record<string, string> = {
    // Metals
    steel_rebar: 'Çelik Donatı (Rebar)',
    steel_structural: 'Yapısal Çelik',
    aluminium: 'Alüminyum',
    aluminum: 'Alüminyum',
    copper: 'Bakır',
    brass: 'Pirinç',
    // Building materials
    cement: 'Çimento',
    cement_clinker: 'Çimento Klinker',
    aggregate: 'Agrega',
    brick: 'Tuğla',
    brick_clay: 'Kil Tuğla',
    ceramic_tile: 'Seramik Karo',
    glass: 'Cam',
    gypsum_board: 'Alçıpan',
    paint: 'Boya',
    wood_timber: 'Kereste',
    plywood: 'Kontrplak',
    mdf: 'MDF',
    asphalt: 'Asfalt',
    // Utilities/waste
    water_supply: 'Şebeke Suyu',
    waste_mixed: 'Karma Atık Bertarafı',
    // Energy/transport basics
    electricity_grid: 'Elektrik (şebeke)',
    diesel_fuel: 'Dizel Yakıt',
    passenger_car: 'Binek Araç',
    natural_gas: 'Doğal Gaz',
    gasoline: 'Benzin',
    // Concrete grades
    concrete: 'Beton',
    concrete_c20: 'Beton C20',
    concrete_c25: 'Beton C25',
    concrete_c30: 'Beton C30'
  };

  const tokenize = (s: string) => s.toLowerCase().normalize('NFKD').replace(/[^a-z0-9çğıöşü\s]/gi, ' ').replace(/\s+/g, ' ').trim();
  const turkishify = (s: string) => {
    // Quick word-level replacements for common English terms
    const map: Record<string, string> = {
      cement: 'çimento',
      clinker: 'klinker',
      ceramic: 'seramik',
      tile: 'karo',
      brick: 'tuğla',
      clay: 'kil',
      brass: 'pirinç',
      glass: 'cam',
      paint: 'boya',
      asphalt: 'asfalt',
      steel: 'çelik',
      structural: 'yapısal',
      rebar: 'donatı',
      aluminium: 'alüminyum',
      aluminum: 'alüminyum',
      copper: 'bakır',
      plywood: 'kontrplak',
      timber: 'kereste',
      board: 'levha',
      gypsum: 'alçı',
      water: 'su',
      supply: 'şebeke',
      mixed: 'karma',
      waste: 'atık',
    };
    const words = tokenize(s).split(' ');
    const tr = words.map((w) => map[w] ?? w).join(' ');
    // Capitalize first letter of each word
    return tr.replace(/(^|\s)([a-zçğıöşü])/g, (m, p1, p2) => p1 + p2.toUpperCase());
  };

  const trLabel = (key?: string, name?: string, category?: string) => {
    const k = (key || category || '').toLowerCase();
    if (k && TR_MAP[k]) return TR_MAP[k];
    // If DB already has a Turkish-looking name, keep it; otherwise try to translate tokens
    const base = (name || k.replace(/_/g, ' ')).trim();
    // Heuristic: if contains any Turkish-specific chars, assume already TR
    if (/[çğıöşüÇĞİÖŞÜ]/.test(base)) return base;
    return turkishify(base);
  };
  useEffect(() => {
    (async () => {
      setLoading(true);
      // Always fetch full list so we can filter in TR on the client reliably
      const [acts, favs] = await Promise.all([
        supabaseBrowser
          .from('activities')
          .select('id, key, name, category, type')
          .order('type', { ascending: true })
          .order('name', { ascending: true }),
        supabaseBrowser.from('user_favorites').select('activity_id')
      ]);
      const rows = (acts.data || []) as Array<{ id: string; key?: string; name?: string; category?: string; type: string }>;
      const translated = rows.map((r) => ({ id: r.id, type: r.type, name: trLabel(r.key, r.name, r.category) }));
      setItems(translated);
      setFavorites(new Set((favs.data || []).map((f: any) => f.activity_id)));
      setLoading(false);
    })();
  }, []);

  // Show selected item's label in the input when value changes
  useEffect(() => {
    if (!value) { return; }
    const it = items.find((x) => x.id === value);
    if (it) setQ(it.name);
  }, [value, items]);

  // Close dropdown on outside click
  useEffect(() => {
    function onDocClick(e: MouseEvent) {
      if (!boxRef.current) return;
      if (!boxRef.current.contains(e.target as Node)) {
        setOpen(false);
        setHighlight(-1);
      }
    }
    document.addEventListener('mousedown', onDocClick);
    return () => document.removeEventListener('mousedown', onDocClick);
  }, []);

  const filtered = useMemo(() => {
    const termRaw = q.trim();
    const term = termRaw.toLowerCase();
    if (!term) return items;
    const tTok = tokenize(term);

    function score(it: { name: string; type: string }) {
      const nameTok = tokenize(it.name);
      const typeTok = tokenize(it.type);
      // Priority rules
      // 1) Token startsWith
      const tokens = nameTok.split(' ');
      const startsToken = tokens.some((tk) => tk.startsWith(tTok));
      // 2) Include anywhere
      const includes = nameTok.includes(tTok) || typeTok.includes(tTok);
      // 3) Special: concrete grades when typing C...
      const isConcreteHint = /^c\s*\d*/i.test(termRaw);
      const isConcreteName = /beton\s*c\d+/i.test(it.name);
      let s = 0;
      if (startsToken) s += 3;
      if (includes) s += 1;
      if (isConcreteHint && isConcreteName) s += 5;
      return s;
    }

    return items
      .filter((it) => tokenize(it.name).includes(tTok) || tokenize(it.type).includes(tTok) || tokenize(it.name).split(' ').some((tk) => tk.startsWith(tTok)))
      .sort((a, b) => score(b) - score(a));
  }, [items, q]);
  const groups: Record<string, { id: string; name: string; type: string }[]> = {};
  for (const it of filtered) {
    groups[it.type] = groups[it.type] || []; groups[it.type].push(it);
  }
  async function toggleFavorite(activityId: string) {
    try {
      if (!activityId) return;
      const isFav = favorites.has(activityId);
      if (isFav) {
        const { error } = await supabaseBrowser
          .from('user_favorites')
          .delete()
          .eq('activity_id', activityId);
        if (!error) {
          const next = new Set(favorites);
          next.delete(activityId);
          setFavorites(next);
        }
      } else {
        const { error } = await supabaseBrowser
          .from('user_favorites')
          .insert({ activity_id: activityId });
        if (!error) {
          const next = new Set(favorites);
          next.add(activityId);
          setFavorites(next);
        }
      }
    } catch {}
  }
  return (
    <div className="space-y-3" ref={boxRef}>
      <div className="relative">
        <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none text-white/50">
          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <circle cx="11" cy="11" r="8"></circle>
            <path d="m21 21-4.3-4.3"></path>
          </svg>
        </div>
        <input
          ref={inputRef}
          value={q}
          onChange={(e) => {
            setQ(e.target.value);
            setOpen(true);
            setHighlight(0);
          }}
          onFocus={() => setOpen(true)}
          onKeyDown={(e) => {
            if (!open && (e.key.length === 1 || e.key === 'Backspace')) setOpen(true);
            if (!open) return;
            if (e.key === 'ArrowDown') { e.preventDefault(); setHighlight((h) => Math.min(h + 1, filtered.length - 1)); }
            if (e.key === 'ArrowUp') { e.preventDefault(); setHighlight((h) => Math.max(h - 1, 0)); }
            if (e.key === 'Enter') {
              e.preventDefault();
              const it = filtered[highlight] || filtered[0];
              if (it) {
                onChange(it.id);
                setQ(it.name);
                setOpen(false);
              }
            }
            if (e.key === 'Escape') { setOpen(false); }
          }}
          placeholder="Aktivite ara..."
          className="w-full rounded-lg bg-white/5 border border-white/10 pl-10 pr-9 py-2.5 focus:outline-none focus:ring-2 focus:ring-leaf-400/30 focus:border-leaf-400/30 transition-all"
        />
        {value ? (
          <button
            type="button"
            title="Seçimi temizle"
            onClick={() => { onChange(''); setQ(''); setOpen(true); setHighlight(0); inputRef.current?.focus(); }}
            className="absolute inset-y-0 right-0 pr-2 flex items-center text-white/60 hover:text-white"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M18 6 6 18" /><path d="m6 6 12 12" />
            </svg>
          </button>
        ) : null}
      </div>
      
      {/* Hidden field to submit selected activity id */}
      <input type="hidden" name="activity_id" value={value || ''} />

      {/* Combobox dropdown */}
      <div className="relative">
        {open && (
          <div className="absolute z-20 mt-1 w-full max-h-72 overflow-auto rounded-lg border border-white/15 bg-emerald-950/95 backdrop-blur-md p-1 shadow-xl">
            {loading ? (
              <div className="px-3 py-2 text-white/70 text-sm">Yükleniyor…</div>
            ) : filtered.length === 0 ? (
              <div className="px-3 py-2 text-amber-200/90 text-sm">Aramanızla eşleşen aktivite bulunamadı</div>
            ) : (
              <div className="divide-y divide-white/10">
                {favorites.size > 0 && items.some((it) => favorites.has(it.id) && tokenize(it.name).includes(tokenize(q))) ? (
                  <div className="py-1">
                    <div className="px-3 pb-1 text-xs uppercase tracking-wide text-white/50">★ Favoriler</div>
                    {items.filter((it) => favorites.has(it.id)).filter((it) => !q || tokenize(it.name).includes(tokenize(q))).map((it) => (
                      <ComboRow key={it.id} it={it} active={filtered[highlight]?.id === it.id} onPick={() => { onChange(it.id); setQ(it.name); setOpen(false); }} onFav={() => toggleFavorite(it.id)} fav={favorites.has(it.id)} />
                    ))}
                  </div>
                ) : null}
                {Object.entries(groups).map(([type, arr]) => (
                  <div key={type} className="py-1">
                    <div className="px-3 pb-1 text-xs uppercase tracking-wide text-white/50">
                      {type === 'energy' ? '⚡ Enerji' : type === 'transport' ? '🚗 Ulaşım' : type === 'materials' ? '📦 Malzeme' : '🔄 Diğer'}
                    </div>
                    {arr.map((it, idx) => {
                      const isActive = filtered[highlight]?.id === it.id;
                      return (
                        <ComboRow key={it.id} it={it} active={isActive} onPick={() => { onChange(it.id); setQ(it.name); setOpen(false); }} onFav={() => toggleFavorite(it.id)} fav={favorites.has(it.id)} />
                      );
                    })}
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>
      
      {loading ? (
        <div className="flex items-center justify-center text-white/60 text-sm py-2">
          <svg className="animate-spin h-4 w-4 mr-2" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Aktiviteler yükleniyor...
        </div>
      ) : (
        <div className="flex items-center justify-between text-xs text-white/60 px-1">
          <span>{filtered.length} aktivite listeleniyor</span>
          {value ? (
            <button type="button" className="text-amber-300 hover:text-amber-200 underline" onClick={() => toggleFavorite(value)}>
              {favorites.has(value) ? 'Favorilerden çıkar' : 'Favorilere ekle'}
            </button>
          ) : null}
        </div>
      )}
    </div>
  );
}

function ComboRow({ it, active, onPick, onFav, fav }: { it: { id: string; name: string; type: string }; active: boolean; onPick: () => void; onFav: () => void; fav: boolean }) {
  return (
    <div
      className={`px-3 py-2 text-sm flex items-center justify-between cursor-pointer rounded-md transition-colors ${active ? 'bg-emerald-800/70 text-white shadow-inner' : 'text-white/90 hover:bg-white/10'}`}
      onMouseDown={(e) => { e.preventDefault(); onPick(); }}
    >
      <span className="truncate">{it.name}</span>
      <button
        type="button"
        title={fav ? 'Favorilerden çıkar' : 'Favorilere ekle'}
        onMouseDown={(e) => { e.preventDefault(); onFav(); }}
        className={`ml-3 text-xs ${fav ? 'text-amber-300' : 'text-white/50 hover:text-white/80'}`}
      >
        {fav ? '★' : '☆'}
      </button>
    </div>
  );
}

import { submitEntryAction } from './server';
import EntryForm from './EntryForm';
import Link from 'next/link';
import { createClient } from '@/lib/server';
import { redirect } from 'next/navigation';
import type { Route } from 'next';

export default async function NewEntryPage({ params, searchParams }: any) {
  const p = params;
  const sp = searchParams || {};
  const error = typeof sp.error === 'string' ? sp.error : '';
  
  // Fetch project information and permissions
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  const { data: project } = await supabase
    .from('projects')
    .select('id, name')
    .eq('id', p.id)
    .maybeSingle();
  let canInsert = false;
  if (user) {
    const { data: membership } = await supabase
      .from('project_members')
      .select('role')
      .eq('project_id', p.id)
      .eq('user_id', user.id)
      .maybeSingle();
    canInsert = membership?.role === 'owner' || membership?.role === 'editor';
  }
  
  return (
    <div className="w-full mx-auto max-w-2xl md:max-w-3xl space-y-6">
      <div className="relative overflow-hidden rounded-xl bg-gradient-to-r from-emerald-900/60 to-ocean-900/60 border border-white/10 shadow-md">
        <div className="absolute inset-0 bg-gradient-to-br from-leaf-500/5 to-ocean-500/5 backdrop-blur-sm"></div>
        
        <div className="relative p-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-1.5 rounded-md bg-gradient-to-br from-leaf-500/20 to-ocean-500/20 border border-white/10">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-leaf-400">
                  <path d="M12 5v14M5 12h14"/>
                </svg>
              </div>
              <div>
                <h1 className="text-2xl font-semibold highlight-text">Yeni Emisyon Kaydı</h1>
                {project && (
                  <p className="text-sm text-white/70 mt-0.5">{project.name}</p>
                )}
              </div>
            </div>
            
            <Link 
              href={`/projects/${p.id}`}
              className="inline-flex items-center gap-2 px-3 py-1.5 rounded-md text-sm text-white/80 hover:text-white border border-white/10 hover:border-white/20 hover:bg-white/10 transition-colors"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="m15 18-6-6 6-6"/>
              </svg>
              <span>Geri Dön</span>
            </Link>
          </div>
        </div>
      </div>
      {!user ? (
        <div className="rounded-lg border border-amber-500/30 bg-amber-500/10 text-amber-100 p-4 text-sm">
          Kayıt eklemek için lütfen giriş yapın.
        </div>
      ) : null}
      {error ? (
        <div className="rounded-lg border border-red-500/30 bg-red-500/10 text-red-200 p-4 text-sm">
          {error}
        </div>
      ) : null}
      {user && !canInsert ? (
        <div className="rounded-lg border border-red-500/30 bg-red-500/10 text-red-200 p-4 text-sm">
          Bu projeye kayıt ekleme yetkiniz yok. Proje sahibi veya editör olarak eklenmelisiniz.
        </div>
      ) : null}
      
      {user && canInsert ? (
        <EntryForm projectId={p.id} action={submitEntryAction} />
      ) : null}
    </div>
  );
}

"use server";
import { createClient } from '@/lib/server';
import { revalidatePath } from 'next/cache';
import { redirect } from 'next/navigation';
import type { Route } from 'next';
import { z } from 'zod';
import { captureServerError } from '@/sentry.server.config';
import { normalizeCategory } from '@/lib/categoryAliases';

const schema = z.object({
  type: z.enum(['energy','transport','materials','other']),
  date: z.string().min(1),
  amount: z.preprocess((v) => Number(v), z.number().positive()),
  unit: z.string().min(1).max(16),
  notes: z.string().max(1000).optional().default('')
});

export async function createEntry(projectId: string, formData: FormData) {
  try {
    const parsed = schema.safeParse({
      type: formData.get('type'),
      date: formData.get('date'),
      amount: formData.get('amount'),
      unit: formData.get('unit'),
      notes: formData.get('notes')
    });
    if (!parsed.success) {
      const msg = parsed.error.issues?.[0]?.message || 'Form geçersiz. Lütfen alanları kontrol edin.';
      return redirect(`/projects/${projectId}/entries/new?error=${encodeURIComponent(msg)}`);
    }
    const { type, date, amount, unit, notes } = parsed.data;

    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) {
      return redirect(`/login?next=${encodeURIComponent(`/projects/${projectId}/entries/new`)}`);
    }

  // Fetch activity (if selected) to drive unit validation and factor selection
  const activityId = (formData.get('activity_id') as string) || '';
  let activity: any = null;
  if (activityId) {
    const { data: act } = await supabase
      .from('activities')
      .select('id, type, scope, category, default_unit, units')
      .eq('id', activityId)
      .maybeSingle();
    activity = act;
  }

  // --- Additional validations: future date, duplicate detection, anomaly detection ---
  // 1) Disallow far-future dates (allow only today or past)
  try {
    const todayStr = new Date().toISOString().slice(0, 10);
    if (date > todayStr) {
      return redirect(`/projects/${projectId}/entries/new?error=${encodeURIComponent('Gelecekteki bir tarih için kayıt oluşturulamaz')}`);
    }
  } catch (e) {
    // If date parsing fails for any reason, let zod validation handle it later
  }

  // Helper utilities
  const toDateString = (d: Date) => d.toISOString().slice(0, 10);
  const computeMedian = (arr: number[]) => {
    if (!arr.length) return NaN;
    const s = [...arr].sort((a, b) => a - b);
    const mid = Math.floor(s.length / 2);
    return s.length % 2 === 0 ? (s[mid - 1] + s[mid]) / 2 : s[mid];
  };

  // 2) Duplicate detection (same project, same type, same unit, near-equal amount, close date)
  const chosenType = activity?.type || type;
  {
    const base = new Date(date);
    const from = new Date(base);
    const to = new Date(base);
    from.setDate(from.getDate() - 3);
    to.setDate(to.getDate() + 3);
    const { data: possibleDupes } = await supabase
      .from('entries')
      .select('id, amount, unit, type, activity_id, date')
      .eq('project_id', projectId)
      .eq('unit', unit)
      .eq('type', chosenType)
      .gte('date', toDateString(from))
      .lte('date', toDateString(to))
      .limit(20);
    const tolerance = Math.max(0.01 * amount, 0.0001);
    const found = (possibleDupes || []).find((e) => {
      const sameActivity = !activity?.id || e.activity_id === activity.id;
      const amtClose = Math.abs(Number(e.amount || 0) - amount) <= tolerance;
      return sameActivity && amtClose;
    });
    if (found) {
      return redirect(`/projects/${projectId}/entries/new?error=${encodeURIComponent('Benzer bir kayıt zaten mevcut. Lütfen girdiyi kontrol edin.')}`);
    }
  }

  // 3) Anomaly detection (simple historical outlier check on same unit/type)
  {
    const { data: recentSameUnit } = await supabase
      .from('entries')
      .select('amount')
      .eq('project_id', projectId)
      .eq('type', chosenType)
      .eq('unit', unit)
      .order('date', { ascending: false })
      .limit(200);
    const amounts = (recentSameUnit || [])
      .map((r: any) => Number(r.amount))
      .filter((v) => Number.isFinite(v) && v > 0);
    if (amounts.length >= 5) {
      const median = computeMedian(amounts);
      if (Number.isFinite(median) && median > 0) {
        const ratio = amount / median;
        // Hard stop for extreme anomalies (100x+ of historical median)
        if (ratio > 100) {
          return redirect(`/projects/${projectId}/entries/new?error=${encodeURIComponent('Girilen miktar alışılmadık derecede yüksek görünüyor. Birimi veya değeri kontrol edin.')}`);
        }
      }
    }
  }

  // Validate unit against activity allowed units if present
  if (activity?.units && Array.isArray(activity.units) && activity.units.length > 0) {
    if (!activity.units.includes(unit)) {
      return redirect(`/projects/${projectId}/entries/new?error=${encodeURIComponent('Seçilen birim aktivite ile uyumlu değil')}`);
    }
  }

  const factorCategory = (activity?.category as string) || type;
  // Pick latest matching factor for category (or type) and region=global
  let factor: any = null;
  if (activity?.id) {
    const q = supabase
      .from('activity_factors')
      .select('factor_id, emission_factors!inner(unit_in, unit_out, value, valid_from, region)')
      .eq('activity_id', activity.id)
      .eq('emission_factors.region', 'global')
      .neq('emission_factors.value', 0)
      .order('emission_factors.valid_from', { ascending: false })
      .limit(1);
    // Date-aware factor: choose factor whose valid_from <= entry date
    if (date) (q as any).lte('emission_factors.valid_from', date);
    let { data: mapped } = await q.maybeSingle();
    if (mapped) factor = (mapped as any).emission_factors;
    // Fallback: ignore date if none found
    if (!factor) {
      const q2 = supabase
        .from('activity_factors')
        .select('factor_id, emission_factors!inner(unit_in, unit_out, value, valid_from, region)')
        .eq('activity_id', activity.id)
        .eq('emission_factors.region', 'global')
        .neq('emission_factors.value', 0)
        .order('emission_factors.valid_from', { ascending: false })
        .limit(1);
      const { data: mapped2 } = await q2.maybeSingle();
      if (mapped2) factor = (mapped2 as any).emission_factors;
    }
  }
  if (!factor) {
    const normalizedCategory = normalizeCategory(factorCategory) || factorCategory;
    const fq = supabase
      .from('emission_factors')
      .select('unit_in, unit_out, value, valid_from')
      .eq('category', normalizedCategory)
      .eq('region', 'global')
      .neq('value', 0)
      .order('valid_from', { ascending: false })
      .limit(1);
    if (date) (fq as any).lte('valid_from', date);
    let resp = await fq.maybeSingle();
    factor = resp.data;
    // Fallback: ignore date if none found
    if (!factor) {
      const fq2 = supabase
        .from('emission_factors')
        .select('unit_in, unit_out, value, valid_from')
        .eq('category', normalizedCategory)
        .eq('region', 'global')
        .neq('value', 0)
        .order('valid_from', { ascending: false })
        .limit(1);
      const resp2 = await fq2.maybeSingle();
      factor = resp2.data;
    }
    // Fallback: relaxed prefix match on category
    if (!factor) {
      const fqp = await supabase
        .from('emission_factors')
        .select('unit_in, unit_out, value, valid_from')
        .ilike('category', `${normalizedCategory}%`)
        .eq('region', 'global')
        .neq('value', 0)
        .order('valid_from', { ascending: false })
        .limit(1)
        .maybeSingle();
      factor = fqp.data;
    }
    // Fallback 2: If still not found and we have an activity with a specific key, try factor by key (e.g., concrete_c30)
    if (!factor && activity?.id) {
      const { data: actKeyRow } = await supabase
        .from('activities')
        .select('key')
        .eq('id', activity.id)
        .maybeSingle();
      const key = actKeyRow?.key as string | undefined;
      if (key) {
        const normalizedKey = normalizeCategory(key) || key;
        const fk = supabase
          .from('emission_factors')
          .select('unit_in, unit_out, value, valid_from')
          .eq('category', normalizedKey)
          .eq('region', 'global')
          .neq('value', 0)
          .order('valid_from', { ascending: false })
          .limit(1);
        if (date) (fk as any).lte('valid_from', date);
        let kresp = await fk.maybeSingle();
        factor = kresp.data;
        if (!factor) {
          const fk2 = await supabase
            .from('emission_factors')
            .select('unit_in, unit_out, value, valid_from')
            .eq('category', normalizedKey)
            .eq('region', 'global')
            .neq('value', 0)
            .order('valid_from', { ascending: false })
            .limit(1)
            .maybeSingle();
          factor = fk2.data;
        }
      }
    }
  }

  let co2e_value: number | null = null;
  let co2e_unit: string | null = null;
  if (factor) {
    // find conversion from provided unit -> factor.unit_in
    let multiplier = 1;
    if (unit !== factor.unit_in) {
      const { data: conv } = await supabase
        .from('unit_conversions')
        .select('multiplier')
        .eq('from_unit', unit)
        .eq('to_unit', factor.unit_in)
        .maybeSingle();
      if (!conv?.multiplier) {
        return redirect(`/projects/${projectId}/entries/new?error=${encodeURIComponent(`'${unit}' biriminden '${factor.unit_in}' birimine dönüşüm bulunamadı`)}`);
      }
      multiplier = Number(conv.multiplier);
    }
    const normalizedAmount = amount * multiplier;
    const raw = normalizedAmount * Number(factor.value);
    // Normalize to kilograms in DB. If factor outputs grams or tons, convert to kg.
    if (factor.unit_out === 'g') {
      co2e_value = raw / 1000;
      co2e_unit = 'kg';
    } else if (factor.unit_out === 't' || factor.unit_out === 'ton' || factor.unit_out === 'tons') {
      co2e_value = raw * 1000;
      co2e_unit = 'kg';
    } else {
      // Assume kg for unknown or 'kg'
      co2e_value = raw;
      co2e_unit = 'kg';
    }
  }

  // Use privileged RPC to avoid client-side RLS edge cases and ensure membership is enforced server-side
  const { data: newId, error } = await supabase.rpc('create_entry_privileged', {
    p_project_id: projectId,
    p_user_id: user.id,
    p_type: activity?.type || type,
    p_date: date,
    p_amount: amount,
    p_unit: unit,
    p_scope: (formData.get('scope') as string) || activity?.scope || null,
    p_category: (formData.get('category') as string) || activity?.category || null,
    p_activity_id: activity?.id || null,
    p_notes: notes,
    p_co2e_value: co2e_value,
    p_co2e_unit: co2e_unit,
  });
  if (error) {
    captureServerError(error, { where: 'createEntry', projectId, activityId, factor_unit_in: factor?.unit_in, unit, code: (error as any).code });
    // Graceful UX: redirect back with friendly message instead of crashing
    const msg = (error as any)?.code === '42501'
      ? 'Bu projeye kayıt ekleme yetkiniz yok. Lütfen proje yöneticisinden yetki isteyin.'
      : (error.message || 'Kayıt oluşturulamadı. Lütfen tekrar deneyin.');
    redirect(`/projects/${projectId}/entries/new?error=${encodeURIComponent(msg)}`);
  }
  revalidatePath(`/projects/${projectId}`);
  if (newId) {
    redirect((`/entries/${newId}#evidence` as unknown) as Route);
  }
  redirect(`/projects/${projectId}?success=true&message=${encodeURIComponent('Kayıt başarıyla oluşturuldu')}`);
  } catch (e: any) {
    // Catch-all: never leave the user without feedback
    try {
      captureServerError(e, { where: 'createEntry.catch', projectId });
    } catch {}
    // Preserve Next.js redirect behavior
    if (e && typeof e === 'object' && typeof (e as any).digest === 'string' && (e as any).digest.includes('NEXT_REDIRECT')) {
      throw e;
    }
    const msg = e?.message || 'Kayıt oluşturulamadı. Lütfen tekrar deneyin.';
    return redirect(`/projects/${projectId}/entries/new?error=${encodeURIComponent(msg)}`);
  }
}

// Top-level server action: reads project id from hidden field to avoid closure serialization issues
export async function submitEntryAction(formData: FormData) {
  'use server';
  const projectId = String(formData.get('project_id') || '');
  if (!projectId) {
    redirect(('/dashboard?error=' + encodeURIComponent('Proje bilgisi eksik')) as Route);
  }
  await createEntry(projectId, formData);
}

