                const percentage = total > 0 ? (v / total) * 100 : 0;
                
                let colorClass = 'bg-leaf-500';
                if (k === 'transport') colorClass = 'bg-blue-500';
                if (k === 'materials') colorClass = 'bg-amber-500';
