          className="form-input"
          value={form.trade}
          onChange={(e) => setForm((f) => ({ ...f, trade: e.target.value }))}
        />
        <input
          type="number"
          min={0}
          name="person_count"
          placeholder="Kişi Sayısı"
          className="form-input"
