        <button type="submit" className="btn-primary" disabled={busy}>+ Ekle</button>
      </form>
    </details>
  );
}

"use client";
import { supabaseBrowser } from '@/lib/client';
import { useEffect, useMemo, useState } from 'react';

interface PhotoItem {
  path: string;
  original_name: string;
}

function fileNameFromKey(key: string) {
  const parts = key.split('/')
  return parts[parts.length - 1] || key;
}

export function DailyLogPhotoGrid({ projectId, logId, keys }: { projectId: string; logId: string; keys: (string | PhotoItem)[] }) {
  const [urls, setUrls] = useState<Record<string, string>>({});
  const [busy, setBusy] = useState<Record<string, boolean>>({});

  const normalizePath = (k: string | PhotoItem): string => (typeof k === 'string' ? k : k.path);
  const displayName = (k: string | PhotoItem): string => (typeof k === 'string' ? fileNameFromKey(k) : (k.original_name || fileNameFromKey(k.path)));

  // Normalize to a list of { path, name }
  const items = useMemo(() => (
    [...keys].map((k) => ({ path: normalizePath(k), name: displayName(k) }))
  ), [keys]);

  // Sort by path for stable ordering
  const sorted = useMemo(() => (
    [...items].sort((a, b) => a.path.localeCompare(b.path))
  ), [items]);

  useEffect(() => {
    let mounted = true;
    (async () => {
      const entries: [string, string][] = [];
      for (const it of sorted) {
        const { data } = await supabaseBrowser.storage
          .from('project-files')
          .createSignedUrl(it.path.replace(/^project-files\//, ''), 60 * 10);
        if (data?.signedUrl) entries.push([it.path, data.signedUrl]);
      }
      if (mounted) setUrls(Object.fromEntries(entries));
    })();
    return () => { mounted = false };
  }, [sorted]);

  async function remove(path: string) {
    setBusy((b) => ({ ...b, [path]: true }));
    try {
      // Remove from daily_logs.photos
      const { data, error: selErr } = await supabaseBrowser.from('daily_logs').select('photos').eq('id', logId).maybeSingle();
      if (selErr) throw selErr;
      const current: any[] = Array.isArray(data?.photos) ? data?.photos : [];
      const next = current.filter((p: any) => (typeof p === 'string' ? p !== path : p?.path !== path));
      const { error: updErr } = await supabaseBrowser.from('daily_logs').update({ photos: next }).eq('id', logId);
      if (updErr) throw updErr;
      // Try delete the object (ignore if fails due to permissions)
      await supabaseBrowser.storage.from('project-files').remove([path.replace(/^project-files\//, '')]);
      window.dispatchEvent(new CustomEvent('app-toast', { detail: { message: 'Silindi', variant: 'success' } }));
      // Optimistic update
      setUrls((u) => { const n = { ...u }; delete n[path]; return n; });
    } catch (e: any) {
      window.dispatchEvent(new CustomEvent('app-toast', { detail: { message: e?.message || 'Silme hatası', variant: 'error' } }));
    } finally {
      setBusy((b) => ({ ...b, [path]: false }));
    }
  }

  if (!sorted.length) return <div className="text-white/60 text-sm">Henüz fotoğraf yok.</div>;

  return (
    <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
      {sorted.map(({ path, name }) => {
        return (
          <div key={path} className="rounded border border-white/10 bg-white/5 overflow-hidden">
            <div className="relative">
              { }
              <img src={urls[path]} alt={name} className="w-full h-32 object-cover" />
              <button disabled={!!busy[path]} onClick={() => remove(path)} className="absolute top-1 right-1 text-xs px-2 py-1 rounded bg-red-600/80">Sil</button>
            </div>
            <div className="px-2 py-1 text-[10px] text-white/70 truncate">{name}</div>
          </div>
        );
      })}
    </div>
  );
}

"use client";

import { supabaseBrowser } from '@/lib/client';
import { useEffect, useState } from 'react';
import { Eye, Download, Image, File } from 'lucide-react';
import { Button } from './button';

interface PhotoItem {
  path: string;
  original_name: string;
}

// Support both old string[] format and new PhotoItem[] format
type PhotoData = string | PhotoItem;

// Utility functions to handle both formats
const getPhotoPath = (photo: PhotoData): string => {
  return typeof photo === 'string' ? photo : photo.path;
};

const getPhotoName = (photo: PhotoData): string => {
  if (typeof photo === 'string') {
    // Extract filename from path for string format
    const fileName = photo.split('/').pop() || photo;
    return fileName;
  }
  return photo.original_name;
};

const normalizeKey = (key: string) => key.replace(/^project-files\//, '');

export function DailyLogPhotoList({ projectId, logId, photos }: { projectId: string; logId: string; photos: PhotoData[] }) {
  // Keep a local copy so we can update UI without a full page reload
  const [items, setItems] = useState<PhotoData[]>(photos);
  const [urls, setUrls] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);
  const [viewingPhoto, setViewingPhoto] = useState<{ url: string; name: string } | null>(null);
  const [deleting, setDeleting] = useState<Record<string, boolean>>({});

  // Sync when props change (e.g., parent refresh)
  useEffect(() => {
    setItems(photos);
  }, [photos]);

  useEffect(() => {
    async function fetchUrls() {
      const client = supabaseBrowser;
      const newUrls: Record<string, string> = {};
      
      console.log('🔍 Fetching URLs for photos:', items);
      
      for (const photo of items) {
        const photoPath = getPhotoPath(photo);
        const cleanPath = normalizeKey(photoPath);
        console.log('🔍 Processing photo:', { photoPath, cleanPath });
        
        const { data, error } = await client.storage.from('project-files').createSignedUrl(cleanPath, 3600);
        console.log('🔍 Supabase response:', { data, error });
        
        if (data?.signedUrl) {
          newUrls[photoPath] = data.signedUrl;
          console.log('✅ URL created for:', photoPath);
        } else {
          console.log('❌ No URL for:', photoPath, error);
        }
      }
      
      console.log('🔍 Final URLs:', newUrls);
      setUrls(newUrls);
      setLoading(false);
    }

    if (items.length > 0) {
      fetchUrls();
    } else {
      setLoading(false);
    }
  }, [items]);

  const handleView = (url: string, fileName: string) => {
    if (!url) return alert('Fotoğraf önizlemesi için URL bulunamadı');
    setViewingPhoto({ url, name: fileName });
  };

  const handleDownload = async (url: string, fileName: string) => {
    if (!url) return alert('İndirme için URL bulunamadı');
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      const downloadUrl = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = downloadUrl;
      a.download = fileName;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      window.URL.revokeObjectURL(downloadUrl);
    } catch (error) {
      console.error('Download failed:', error);
      // Fallback: open in new tab
      window.open(url, '_blank');
    }
  };

  const handleDelete = async (photoPath: string) => {
    try {
      const client = supabaseBrowser;

      // Optimistic UI update
      const prevItems = items;
      const prevUrls = urls;
      const updatedItems = prevItems.filter(p => getPhotoPath(p) !== photoPath);
      const updatedUrls = { ...prevUrls } as Record<string, string>;
      delete updatedUrls[photoPath];

      setDeleting((d) => ({ ...d, [photoPath]: true }));
      setItems(updatedItems);
      setUrls(updatedUrls);
      if (viewingPhoto && urls[photoPath] === viewingPhoto.url) {
        setViewingPhoto(null);
      }

      // Remove from storage
      const cleanPath = normalizeKey(photoPath);
      const { error: storageError } = await client.storage.from('project-files').remove([cleanPath]);
      if (storageError) throw storageError;

      // Persist DB change
      const { error } = await client
        .from('daily_logs')
        .update({ photos: updatedItems })
        .eq('id', logId);
      if (error) throw error;
    } catch (error) {
      console.error('Error deleting photo:', error);
      alert('Fotoğraf silinirken bir hata oluştu');
      // Revert UI on failure
      setItems(photos);
      // Refetch URLs to be safe
      setLoading(true);
      setUrls({});
    }
    finally {
      setDeleting((d) => ({ ...d, [photoPath]: false }));
    }
  };

  if (loading) {
    return <div className="text-white/70">Fotoğraflar yükleniyor...</div>;
  }

  if (items.length === 0) {
    return <div className="text-white/70">Henüz fotoğraf eklenmemiş</div>;
  }

  // Sort photos by name to avoid mixed ordering
  const sortedPhotos = [...items].sort((a, b) => getPhotoName(a).localeCompare(getPhotoName(b)));

  return (
    <>
      <ul className="space-y-2">
        {sortedPhotos.map((photo, index) => {
          const photoPath = getPhotoPath(photo);
          const photoName = getPhotoName(photo);
          const fileUrl = urls[photoPath];
          
          return (
            <li key={photoPath + index} className="rounded-lg border border-white/10 p-4 bg-white/5 backdrop-blur-sm">
              <div className="flex items-center justify-between gap-3">
                <div className="flex items-center gap-3 min-w-0 flex-1">
                  {/* Photo thumbnail */}
                  <div className="flex-shrink-0">
                    {fileUrl ? (
                      <img src={fileUrl} alt="thumbnail" className="h-12 w-12 object-cover rounded border border-white/20" />
                    ) : (
                      <div className="h-12 w-12 bg-white/10 rounded flex items-center justify-center">
                        <Image size={16} className="text-leaf-400" />
                      </div>
                    )}
                  </div>
                  
                  {/* Photo info */}
                  <div className="min-w-0 flex-1">
                    <div className="text-sm font-medium text-white truncate" title={photoName}>
                      {photoName}
                    </div>
                    <div className="flex items-center gap-2 text-xs text-white/60 mt-1">
                      <span>Fotoğraf</span>
                      <span>•</span>
                      <span>JPG</span>
                    </div>
                  </div>
                </div>
                
                {/* Action buttons */}
                <div className="flex items-center gap-2 flex-shrink-0">
                  {fileUrl && (
                    <>
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => handleView(fileUrl, photoName)}
                        className="h-8 px-3 bg-white/5 border-white/20 hover:bg-white/10 hover:border-white/30"
                        title="Görüntüle"
                      >
                        <Eye size={14} className="text-leaf-400" />
                      </Button>
                      
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => handleDownload(fileUrl, photoName)}
                        className="h-8 px-3 bg-white/5 border-white/20 hover:bg-white/10 hover:border-white/30"
                        title="İndir"
                      >
                        <Download size={14} className="text-ocean-400" />
                      </Button>
                    </>
                  )}
                  
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => handleDelete(photoPath)}
                    disabled={!!deleting[photoPath]}
                    className="h-8 px-3 bg-red-500/10 border-red-500/30 hover:bg-red-500/20 hover:border-red-500/50 text-red-400"
                    title="Sil"
                  >
                    {deleting[photoPath] ? 'Siliniyor…' : 'Sil'}
                  </Button>
                </div>
              </div>
            </li>
          );
        })}
      </ul>

      {/* Photo viewer modal - Same as Evidence system */}
      {viewingPhoto && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white/10 backdrop-blur-lg rounded-lg border border-white/20 max-w-4xl max-h-[90vh] w-full overflow-hidden">
            {/* Header */}
            <div className="flex items-center justify-between p-4 border-b border-white/20">
              <h3 className="text-lg font-medium text-white truncate">
                {viewingPhoto.name}
              </h3>
              <div className="flex items-center gap-2">
                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => handleDownload(viewingPhoto.url, viewingPhoto.name)}
                  className="bg-white/5 border-white/20 hover:bg-white/10"
                >
                  <Download size={14} className="mr-1" />
                  İndir
                </Button>
                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => setViewingPhoto(null)}
                  className="bg-white/5 border-white/20 hover:bg-white/10"
                >
                  Kapat
                </Button>
              </div>
            </div>
            
            {/* Content */}
            <div className="p-4 max-h-[calc(90vh-120px)] overflow-auto">
              <img 
                src={viewingPhoto.url} 
                alt={viewingPhoto.name}
                className="max-w-full h-auto mx-auto rounded"
              />
            </div>
          </div>
        </div>
      )}
    </>
  );
}

"use client";
import { useEffect, useMemo, useRef, useState } from "react";

type Props = {
  from?: string; // yyyy-mm-dd
  to?: string;   // yyyy-mm-dd
  onChange: (from: string, to: string) => void;
  className?: string;
  label?: string;
};

export default function DateRangePicker({ from, to, onChange, className = "", label = "Tarih Aralığı" }: Props) {
  const [open, setOpen] = useState(false);
  const [draftFrom, setDraftFrom] = useState<string>(from || "");
  const [draftTo, setDraftTo] = useState<string>(to || "");
  const panelRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => { setDraftFrom(from || ""); }, [from]);
  useEffect(() => { setDraftTo(to || ""); }, [to]);

  // Close on outside click / escape
  useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => { if (e.key === "Escape") setOpen(false); };
    const onClick = (e: MouseEvent) => {
      if (!panelRef.current) return;
      if (!panelRef.current.contains(e.target as Node)) setOpen(false);
    };
    document.addEventListener("keydown", onKey);
    document.addEventListener("mousedown", onClick);
    return () => { document.removeEventListener("keydown", onKey); document.removeEventListener("mousedown", onClick); };
  }, [open]);

  const labelText = useMemo(() => {
    if (!from && !to) return "Tarih seçin";
    const fmt = (s?: string) => {
      if (!s) return "";
      const d = new Date(s);
      if (Number.isNaN(d.getTime())) return s;
      return d.toLocaleDateString("tr-TR");
    };
    return `${fmt(from)} – ${fmt(to)}`.trim();
  }, [from, to]);

  const apply = () => {
    if (!draftFrom || !draftTo) {
      onChange(draftFrom || "", draftTo || "");
      setOpen(false);
      return;
    }
    // ensure draftFrom <= draftTo
    const df = new Date(draftFrom);
    const dt = new Date(draftTo);
    if (df > dt) {
      // swap
      onChange(draftTo, draftFrom);
    } else {
      onChange(draftFrom, draftTo);
    }
    setOpen(false);
  };

  const clear = () => {
    setDraftFrom("");
    setDraftTo("");
    onChange("", "");
    setOpen(false);
  };

  // Quick presets
  const todayIso = () => new Date().toISOString().slice(0,10);
  const toIso = (d: Date) => d.toISOString().slice(0,10);
  const startOfMonth = (d = new Date()) => new Date(d.getFullYear(), d.getMonth(), 1);
  const endOfMonth = (d = new Date()) => new Date(d.getFullYear(), d.getMonth() + 1, 0);
  const lastMonthRange = () => {
    const d = new Date();
    const start = new Date(d.getFullYear(), d.getMonth() - 1, 1);
    const end = new Date(d.getFullYear(), d.getMonth(), 0);
    return { from: toIso(start), to: toIso(end) };
  };
  const thisYearRange = () => {
    const d = new Date();
    const start = new Date(d.getFullYear(), 0, 1);
    const end = new Date(d.getFullYear(), 11, 31);
    return { from: toIso(start), to: toIso(end) };
  };
  const last7Days = () => {
    const end = new Date();
    const start = new Date();
    start.setDate(end.getDate() - 6);
    return { from: toIso(start), to: toIso(end) };
  };
  const setPreset = (range: { from: string; to: string }, applyNow = true) => {
    setDraftFrom(range.from);
    setDraftTo(range.to);
    if (applyNow) {
      onChange(range.from, range.to);
      setOpen(false);
    }
  };

  return (
    <div className={`relative ${className}`}>
      <div className="grid gap-2">
        {label && <label className="text-sm text-white/80">{label}</label>}
        <button
          type="button"
          onClick={() => setOpen((v) => !v)}
          className="flex items-center justify-between w-full bg-transparent border border-white/20 rounded-md px-3 py-2 text-left hover:border-white/30 focus:outline-none focus:ring-2 focus:ring-leaf-500/60 transition"
        >
          <span className="truncate text-white/90 text-sm">{labelText}</span>
          <svg className="w-4 h-4 text-white/60 shrink-0" viewBox="0 0 20 20" fill="currentColor" aria-hidden>
            <path fillRule="evenodd" d="M5.23 7.21a.75.75 0 011.06.02L10 10.94l3.71-3.71a.75.75 0 111.06 1.06l-4.24 4.24a.75.75 0 01-1.06 0L5.21 8.29a.75.75 0 01.02-1.08z" clipRule="evenodd" />
          </svg>
        </button>
      </div>

      {open && (
        <div ref={panelRef} className="absolute z-50 mt-2 w-[min(420px,90vw)] bg-black/90 backdrop-blur border border-white/10 rounded-lg shadow-xl p-4">
          <div className="flex flex-wrap gap-2 mb-3">
            <button type="button" className="text-xs px-2 py-1 rounded-md border border-white/15 text-white/80 hover:bg-white/5 focus:outline-none focus:ring-2 focus:ring-leaf-500/60" onClick={() => setPreset(last7Days())}>Son 7 gün</button>
            <button type="button" className="text-xs px-2 py-1 rounded-md border border-white/15 text-white/80 hover:bg-white/5 focus:outline-none focus:ring-2 focus:ring-leaf-500/60" onClick={() => setPreset({ from: toIso(startOfMonth()), to: toIso(endOfMonth()) })}>Bu ay</button>
            <button type="button" className="text-xs px-2 py-1 rounded-md border border-white/15 text-white/80 hover:bg-white/5 focus:outline-none focus:ring-2 focus:ring-leaf-500/60" onClick={() => setPreset(lastMonthRange())}>Geçen ay</button>
            <button type="button" className="text-xs px-2 py-1 rounded-md border border-white/15 text-white/80 hover:bg-white/5 focus:outline-none focus:ring-2 focus:ring-leaf-500/60" onClick={() => setPreset(thisYearRange())}>Bu yıl</button>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="grid gap-2">
              <label className="text-xs text-white/60">Başlangıç</label>
              <input
                type="date"
                value={draftFrom}
                onChange={(e) => setDraftFrom(e.target.value)}
                className="bg-transparent border border-white/20 rounded-md px-3 py-2 hover:border-white/30 focus:outline-none focus:ring-2 focus:ring-leaf-500/60"
              />
            </div>
            <div className="grid gap-2">
              <label className="text-xs text-white/60">Bitiş</label>
              <input
                type="date"
                value={draftTo}
                onChange={(e) => setDraftTo(e.target.value)}
                className="bg-transparent border border-white/20 rounded-md px-3 py-2 hover:border-white/30 focus:outline-none focus:ring-2 focus:ring-leaf-500/60"
              />
            </div>
          </div>
          <div className="flex items-center gap-2 mt-4">
            <button type="button" onClick={clear} className="text-xs text-white/60 hover:text-white/80 underline underline-offset-4">Temizle</button>
            <div className="ml-auto flex gap-2">
              <button type="button" onClick={() => setOpen(false)} className="px-3 py-2 text-sm rounded-md border border-white/15 text-white/80 hover:bg-white/5">Vazgeç</button>
              <button type="button" onClick={apply} className="px-3 py-2 text-sm rounded-md bg-leaf-500/90 hover:bg-leaf-500 text-black font-medium">Uygula</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

