"use client";

import { useMemo } from 'react';
import { formatCo2eTons } from '@/lib/units';

interface BeforeAfterProps {
  beforeKg: number;
  afterKg: number;
  height?: number;
  labels?: { before: string; after: string };
}

export default function BeforeAfter({ beforeKg, afterKg, height = 160, labels = { before: 'Mevcut', after: 'Öneri' } }: BeforeAfterProps) {
  const before = useMemo(() => formatCo2eTons(beforeKg, 2), [beforeKg]);
  const after = useMemo(() => formatCo2eTons(afterKg, 2), [afterKg]);
  const reduction = useMemo(() => {
    const diffKg = Math.max(0, beforeKg - afterKg);
    const pct = beforeKg > 0 ? (diffKg / beforeKg) * 100 : 0;
    return { diff: formatCo2eTons(diffKg, 2), pct: pct.toFixed(1) };
  }, [beforeKg, afterKg]);

  // Simple flex bars, no canvas needed here
  const maxKg = Math.max(beforeKg, afterKg, 1);
  const beforePct = Math.round((beforeKg / maxKg) * 100);
  const afterPct = Math.round((afterKg / maxKg) * 100);

  return (
    <div className="space-y-3">
      <div className="grid grid-cols-2 gap-4">
        <div>
          <div className="text-xs text-white/60 mb-1">{labels.before}</div>
          <div className="bg-white/10 rounded-md h-8 relative overflow-hidden">
            <div className="bg-emerald-500/80 h-full" style={{ width: `${beforePct}%` }} />
          </div>
          <div className="text-xs mt-1">{before.value} {before.unit}</div>
        </div>
        <div>
          <div className="text-xs text-white/60 mb-1">{labels.after}</div>
          <div className="bg-white/10 rounded-md h-8 relative overflow-hidden">
            <div className="bg-sky-500/80 h-full" style={{ width: `${afterPct}%` }} />
          </div>
          <div className="text-xs mt-1">{after.value} {after.unit}</div>
        </div>
      </div>
      <div className="text-sm text-white/80">
        Potansiyel azalma: <span className="font-medium text-emerald-300">{reduction.diff.value} {reduction.diff.unit}</span> ({reduction.pct}%)
      </div>
    </div>
  );
}

"use client";

import { useEffect, useRef } from 'react';
import { formatCo2eTons } from '@/lib/units';

export interface LinePoint { label: string; value: number }

interface LineChartProps {
  data: LinePoint[];
  height?: number;
}

// Lightweight, crisp line chart for monthly totals (expects <= 24 points)
export default function LineChart({ data, height = 220 }: LineChartProps) {
  const ref = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = ref.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const dpr = Math.max(1, (globalThis as any).devicePixelRatio || 1);

    const draw = () => {
      // CSS size: width from layout, height from prop
      const cssWidth = Math.max(0, Math.floor(canvas.clientWidth || 0));
      const cssHeight = height;

      // Backing store size for crispness
      const targetW = Math.max(1, Math.floor(cssWidth * dpr));
      const targetH = Math.max(1, Math.floor(cssHeight * dpr));
      if (canvas.width !== targetW) canvas.width = targetW;
      if (canvas.height !== targetH) canvas.height = targetH;
      canvas.style.width = cssWidth + 'px';
      canvas.style.height = cssHeight + 'px';

      // Reset transform and scale by DPR
      ctx.setTransform(1, 0, 0, 1, 0, 0);
      ctx.scale(dpr, dpr);

      const width = cssWidth;
      const h = cssHeight;

      // Clear
      ctx.clearRect(0, 0, width, h);

      // Style presets
      const axisColor = 'rgba(255,255,255,0.18)';
      const gridColor = 'rgba(255,255,255,0.10)';
      const textColor = 'rgba(255,255,255,0.75)';
      const subText = 'rgba(255,255,255,0.6)';
      const lineColor = 'rgba(56,189,248,0.95)'; // sky-400
      const fillTop = 'rgba(56,189,248,0.28)';
      const fillBottom = 'rgba(56,189,248,0.00)';

      if (!data || data.length === 0) {
        ctx.fillStyle = subText;
        ctx.font = '12px Inter, ui-sans-serif, system-ui';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText('Veri yok', width / 2, h / 2);
        return;
      }

      const padding = { top: 16, right: 18, bottom: 44, left: 58 };
      const plotW = Math.max(1, width - padding.left - padding.right);
      const plotH = Math.max(1, h - padding.top - padding.bottom);

      const values = data.map(d => d.value);
      const maxV = Math.max(1, Math.max(...values));

      // y-axis grid lines and labels (5 ticks)
      ctx.strokeStyle = gridColor;
      ctx.lineWidth = 1;
      ctx.font = '12px Inter, ui-sans-serif, system-ui';
      ctx.fillStyle = subText;
      ctx.textAlign = 'right';
      ctx.textBaseline = 'middle';
      const ticks = 4;
      for (let i = 0; i <= ticks; i++) {
        const ratio = i / ticks;
        const rawY = padding.top + plotH - ratio * plotH;
        const y = Math.round(rawY) + 0.5; // crisp line
        ctx.beginPath();
        ctx.moveTo(padding.left, y);
        ctx.lineTo(width - padding.right, y);
        ctx.stroke();

        const v = maxV * ratio;
        const t = formatCo2eTons(v, 2);
        ctx.fillText(`${t.value}`, padding.left - 8, rawY);
      }

      // x-axis labels (sample to avoid overlap)
      const n = data.length;
      const stepX = plotW / Math.max(1, n - 1);
      const minLabelSpacing = 64; // px
      const maxLabels = Math.max(2, Math.floor(plotW / minLabelSpacing));
      const labelStep = Math.max(1, Math.ceil(n / maxLabels));

      ctx.fillStyle = textColor;
      ctx.font = '12px Inter, ui-sans-serif, system-ui';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'alphabetic';
      for (let i = 0; i < n; i += 1) {
        if (i % labelStep !== 0 && i !== n - 1) continue; // show sampled + last
        const x = padding.left + i * stepX;
        const label = data[i].label; // e.g. '2025-01'
        ctx.fillText(label, x, h - 10);
      }

      // Area fill under line
      const grad = ctx.createLinearGradient(0, padding.top, 0, padding.top + plotH);
      grad.addColorStop(0, fillTop);
      grad.addColorStop(1, fillBottom);

      // Line path
      ctx.lineWidth = 2.25;
      ctx.lineJoin = 'round';
      ctx.lineCap = 'round';

      ctx.beginPath();
      for (let i = 0; i < n; i++) {
        const x = padding.left + i * stepX;
        const y = padding.top + plotH - (values[i] / maxV) * plotH;
        if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
      }
      // Stroke
      ctx.strokeStyle = lineColor;
      ctx.stroke();

      // Fill
      ctx.lineTo(padding.left + (n - 1) * stepX, padding.top + plotH);
      ctx.lineTo(padding.left, padding.top + plotH);
      ctx.closePath();
      ctx.fillStyle = grad;
      ctx.fill();

      // Points
      for (let i = 0; i < n; i++) {
        const x = padding.left + i * stepX;
        const y = padding.top + plotH - (values[i] / maxV) * plotH;
        ctx.beginPath();
        ctx.arc(x, y, 3.25, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(16,185,129,0.95)'; // emerald-500
        ctx.fill();
        ctx.strokeStyle = '#0b1220'; // subtle dark outline to increase contrast
        ctx.lineWidth = 1.5;
        ctx.stroke();
      }
    };

    // Initial draw
    draw();

    // Redraw on resize for crispness/responsiveness
    const ro = new ResizeObserver(() => draw());
    ro.observe(canvas);
    return () => ro.disconnect();
  }, [data, height]);

  return (
    <div className="w-full">
      <canvas
        ref={ref}
        className="w-full max-w-full block"
        style={{ height }}
      />
      <div className="mt-1 text-xs text-white/60">Y ekseni: tCO2e</div>
    </div>
  );
}

import type { PostgrestSingleResponse } from '@supabase/supabase-js';

export type EmissionFactor = {
  unit_in: string;
  unit_out: string;
  value: number | string;
};

export function pickFactorByCategory<T extends { category?: string; region?: string; valid_from?: string }>(
  factors: Array<EmissionFactor & T>,
  category: string,
  region: string = 'global'
): EmissionFactor | null {
  const filtered = factors.filter((f) => (f as any).category === category && (f as any).region === region);
  if (filtered.length === 0) return null;
  // newest by valid_from desc
  filtered.sort((a: any, b: any) => (new Date(b.valid_from || 0).getTime() - new Date(a.valid_from || 0).getTime()));
  const f = filtered[0];
  return { unit_in: f.unit_in, unit_out: f.unit_out, value: Number(f.value) };
}

export function convertAmount(amount: number, fromUnit: string, toUnit: string, conversions: Array<{ from_unit: string; to_unit: string; multiplier: number | string }>): number | null {
  if (fromUnit === toUnit) return amount;
  const found = conversions.find((c) => c.from_unit === fromUnit && c.to_unit === toUnit);
  if (!found) return null;
  const mult = Number(found.multiplier);
  return amount * mult;
}

export function computeCo2e(
  amount: number,
  providedUnit: string,
  factor: EmissionFactor,
  conversions: Array<{ from_unit: string; to_unit: string; multiplier: number | string }>
): { value: number; unit: string } | null {
  let normalized = amount;
  if (providedUnit !== factor.unit_in) {
    const conv = convertAmount(amount, providedUnit, factor.unit_in, conversions);
    if (conv == null) return null;
    normalized = conv;
  }
  const value = normalized * Number(factor.value);
  return { value, unit: factor.unit_out };
}

import { describe, it, expect } from 'vitest';
import { Opportunity } from '@/lib/opportunities';

// We will import private helpers by re-implementing minimal scenarios via public API where possible.
// For speed, we simulate the rule logic using small helper functions embedded here mirroring the engine's behavior.

type EntryLite = { co2e_value: number; category?: string | null; activities?: { key?: string | null } | null };

function groupByCategory(entries: EntryLite[]) {
  const map = new Map<string, number>();
  for (const e of entries) {
    const keyRaw = e.activities?.key || e.category || 'unknown';
    const key = String(keyRaw);
    const v = Number(e.co2e_value) || 0;
    if (!v) continue;
    map.set(key, (map.get(key) || 0) + v);
  }
  return map;
}

function findTopCategoryShare(catMap: Map<string, number>) {
  let topKey = '';
  let topVal = 0;
  let total = 0;
  for (const [, v] of catMap) total += v;
  for (const [k, v] of catMap) { if (v > topVal) { topVal = v; topKey = k; } }
  const share = total > 0 ? topVal / total : 0;
  return { topKey, topVal, total, share };
}

describe('Opportunities rules (unit)', () => {
  it('high concentration triggers when a category exceeds 60%', () => {
    const entries: EntryLite[] = [
      { co2e_value: 600, category: 'concrete' },
      { co2e_value: 100, category: 'steel_rebar' },
      { co2e_value: 300, category: 'transport' },
    ];
    const cat = groupByCategory(entries);
    const { topKey, share } = findTopCategoryShare(cat);
    expect(topKey).toBe('concrete');
    expect(share).toBeCloseTo(0.6, 2); // exactly 60%
  });

  it('self-benchmark detects >20% increase', () => {
    const prev30 = 1000; // kg
    const last30 = 1300; // kg
    const increase = last30 - prev30;
    const ratio = increase / prev30;
    expect(ratio).toBe(0.3);
    expect(ratio > 0.2).toBe(true);
  });

  it('rebar alternative triggers with significant share or absolute threshold', () => {
    const entries: EntryLite[] = [
      { co2e_value: 5000, category: 'steel_rebar' },
      { co2e_value: 10000, category: 'concrete' },
    ];
    const cat = groupByCategory(entries);
    const total = Array.from(cat.values()).reduce((s, v) => s + v, 0);
    const rebar = cat.get('steel_rebar') || 0;
    const isSignificant = rebar >= 2000 || (total > 0 && (rebar / total) >= 0.1);
    expect(isSignificant).toBe(true);
  });
});
